// ============================================================
// JSONKB v1 — PLANETS + MOONS (Bodies)
// Inputs (by node name):
// - Bodies – Detail
// Output:
// - jsonkb (object), jsonkb_file_path, slug, folder, etc.
// ============================================================

// Pull body detail row
const bodyItems = $items("Bodies – Detail");
if (!bodyItems || bodyItems.length === 0) {
  throw new Error('JSONKB Bodies: Missing input from node "Bodies – Detail".');
}
const row = bodyItems[0].json;


// ---------- Parse locations list ----------
let locations = [];
if (Array.isArray(row.locations_list)) {
  locations = row.locations_list;
} else if (typeof row.locations_list === 'string') {
  try { locations = JSON.parse(row.locations_list); } catch (e) { locations = []; }
} else if (row.locations_list && typeof row.locations_list === 'object') {
  locations = Object.values(row.locations_list);
}

locations = (locations || [])
  .map(n => String(n || '').trim())
  .filter(n => n.length > 0)
  .sort((a, b) => a.localeCompare(b, undefined, { sensitivity: 'base' }));

const totalLocations = Number(row.locations_total ?? locations.length) || 0;


// ---------- Classify body: planet vs moon ----------
const kindRaw = String(row.body_kind || '').toLowerCase();
const isMoon = kindRaw.includes('moon');

const entity_type = isMoon ? 'moon' : 'planet';
const folderSegment = isMoon ? 'moons' : 'planets';
const bodyTypeDisplay = isMoon ? 'Moon' : 'Planet';

// ---------- Slug ----------
const slug = String(row.slug || row.name || '')
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

if (!slug) {
  throw new Error('JSONKB Bodies: slug is empty (cannot write JSONKB file).');
}


const kb_links = {
  kb_page_path: `/kb/${entity_type}/${slug}`,
  kb_browse_path: `/browse?category=${entity_type}`,
};

// ---------- Deterministic kb_text ----------
const name = row.name || `Unknown ${bodyTypeDisplay}`;
const systemName = row.system_name || 'Unknown system';

const kb_text =
  `${name} is a ${bodyTypeDisplay.toLowerCase()} in the ${systemName} system with ${totalLocations} known locations.`;

// ---------- entity_metadata ----------
const entity_metadata = {
  uex_body_id: row.uex_body_id != null ? Number(row.uex_body_id) : null,
  system_name: systemName,
  body_type: entity_type,
  location_count: totalLocations,
  locations, // list of names
};

// ---------- rag_hints (stub) ----------
const rag_hints = {
  sql_hints: [
    {
      id: "body.core",
      description: "Fetch a planet or moon by body id.",
      params: [{"name":"body_id","type":"uuid","required":true}],
      sql_template: `SELECT b.id, b.name, b.slug, b.system_id, b.parent_body_id, b.body_type
FROM bodies b
WHERE b.id = :body_id
LIMIT 1;`
    },
    {
      id: "body.moons",
      description: "List moons for a planet body.",
      params: [{"name":"planet_body_id","type":"uuid","required":true}],
      sql_template: `SELECT b.id, b.name, b.slug
FROM bodies b
WHERE b.parent_body_id = :planet_body_id
  AND lower(b.body_type) = 'moon'
ORDER BY b.name;`
    },
    {
      id: "body.parent_planet",
      description: "Fetch the parent planet for a moon.",
      params: [{"name":"moon_body_id","type":"uuid","required":true}],
      sql_template: `SELECT p.id, p.name, p.slug
FROM bodies m
JOIN bodies p ON p.id = m.parent_body_id
WHERE m.id = :moon_body_id
  AND lower(m.body_type) = 'moon'
LIMIT 1;`
    },
  ],
  notes: null
};

// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Planet_Moons v1',
  game_version: row.game_version || null,
  is_live_only: true,
};


const jsonkb = {
  kb_version: '1.0',

  entity_type,
  entity_id: row.id || null,
  entity_slug: slug,
  entity_name: name,

  source: 'uex',
source_id: row.uex_body_id != null ?  `${entity_type}:${Number(row.uex_body_id)}` : null,

  source_table: 'bodies',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

function stableStringify(value) {
  const seen = new WeakSet();

  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null; // defensive; shouldn’t happen
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm); // keep array order

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }

    return v;
  }

  return JSON.stringify(norm(value));
}

// ---------- hash (FNV32 doubled => 16 hex chars) ----------
function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}
function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);
// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/${entity_type}/${slug}`;

return [
  {
    json: {
      body_id: row.id,
      slug,
      name,
      body_type: bodyTypeDisplay,
      folder: folderSegment,

      jsonkb,
      jsonkb_file_path,
    },
  },
];

